// 精确提取公式编号并检查中水规范符合性
var doc = Application.ActiveDocument;
var formulas = [];
var sections = doc.Sections;

for (var s = 0; s < sections.Count; s++) {
    var section = sections.Item(s);
    var paragraphs = section.Paragraphs;

    for (var i = 0; i < paragraphs.Count; i++) {
        try {
            var para = paragraphs.Item(i);
            var text = para.Range.Text;

            // 精确匹配公式编号格式：(1), (2-1), (3.1), 式(1), Eq.(1)
            // 排除纯数字、年份、版本号等
            var regex = /\((\d+(-\d+)?|\d+\.\d+)\)|式\s*\((\d+(-\d+)?|\d+\.\d+)\)|Eq\.?\s*\((\d+(-\d+)?|\d+\.\d+)\)/gi;
            var matches = text.match(regex);

            if (matches) {
                for (var j = 0; j < matches.length; j++) {
                    var num = matches[j].replace(/[()式Eq\.]/g, '').trim();
                    formulas.push({
                        section: s,
                        paragraph: i,
                        raw: matches[j],
                        number: num,
                        preview: text.substring(0, 50).replace(/[\r\n]/g, ' ')
                    });
                }
            }
        } catch (e) {}
    }
}

// 按编号分组统计
var byNumber = {};
for (var k = 0; k < formulas.length; k++) {
    var num = formulas[k].number;
    if (!byNumber[num]) byNumber[num] = [];
    byNumber[num].push(formulas[k]);
}

// 检查连续性
var numbers = Object.keys(byNumber).sort(function(a, b) {
    var na = a.split('-');
    var nb = b.split('-');
    var pa = parseInt(na[0]), pb = parseInt(nb[0]);
    if (pa !== pb) return pa - pb;
    return na[1] ? parseInt(na[1]) : 0 - (nb[1] ? parseInt(nb[1]) : 0);
});

return {
    total: formulas.length,
    uniqueNumbers: numbers,
    distribution: byNumber,
    issues: []
};

// 精确提取公式编号并检查中水规范符合性（修正段落获取方式）
var doc = Application.ActiveDocument;
var formulas = [];

if (!doc) {
    return { error: "未找到活动文档" };
}

// 使用Content范围遍历段落
var content = doc.Content;
if (!content) {
    return { error: "文档内容为空" };
}

var paragraphs = content.Paragraphs;
if (!paragraphs || paragraphs.Count === 0) {
    // 尝试直接遍历Sections
    var sections = doc.Sections;
    if (sections && sections.Count > 0) {
        for (var s = 0; s < sections.Count; s++) {
            var section = sections.Item(s);
            var secPara = section.Paragraphs;
            if (secPara && secPara.Count > 0) {
                paragraphs = secPara;
                break;
            }
        }
    }
}

if (!paragraphs || paragraphs.Count === 0) {
    return { error: "无法获取段落集合", hasContent: !!content, paraCount: paragraphs ? paragraphs.Count : 0 };
}

for (var i = 1; i <= paragraphs.Count; i++) {
    try {
        var para = paragraphs.Item(i);
        var text = "";

        if (para.Range && para.Range.Text) {
            text = para.Range.Text;
        } else if (para.Text) {
            text = para.Text;
        }

        if (!text || text.length < 2) continue;

        // 精确匹配公式编号格式：(1), (2-1), (3.1), 式(1), Eq.(1)
        var regex = /\((\d+(-\d+)?|\d+\.\d+)\)|式\s*\((\d+(-\d+)?|\d+\.\d+)\)|Eq\.?\s*\((\d+(-\d+)?|\d+\.\d+)\)/gi;
        var matches = text.match(regex);

        if (matches) {
            for (var j = 0; j < matches.length; j++) {
                var num = matches[j].replace(/[()式Eq\.]/g, '').trim();
                formulas.push({
                    index: i,
                    raw: matches[j],
                    number: num,
                    preview: text.substring(0, 40).replace(/[\r\n]/g, ' ') + '...'
                });
            }
        }
    } catch (e) {}
}

// 按编号分组
var byNumber = {};
for (var k = 0; k < formulas.length; k++) {
    var num = formulas[k].number;
    if (!byNumber[num]) byNumber[num] = [];
    byNumber[num].push(formulas[k]);
}

// 排序编号
var numbers = Object.keys(byNumber).sort(function(a, b) {
    var na = a.split('-');
    var nb = b.split('-');
    var pa = parseInt(na[0]), pb = parseInt(nb[0]);
    if (pa !== pb) return pa - pb;
    var sa = na[1] ? parseInt(na[1]) : 0;
    var sb = nb[1] ? parseInt(nb[1]) : 0;
    return sa - sb;
});

return {
    total: formulas.length,
    uniqueNumbers: numbers,
    countPerNumber: numbers.map(function(n) { return { num: n, count: byNumber[n].length }; }),
    samples: formulas.slice(0, 20)
};
